class SimpleUserStore:
    def __init__(self):
        self.users: Dict[str, Dict[str, Any]] = {}

    def get_or_create_user(self, saml_user: SAMLUser) -> Dict[str, Any]:
        username = saml_user.name_id
        if not username:
            for key in ("email", "mail", "userPrincipalName", "uid", "username"):
                if key in saml_user.attributes and saml_user.attributes[key]:
                    username = saml_user.attributes[key][0]
                    break
        if not username:
            raise SAMLAuthenticationError("Unable to determine username from SAML assertion")

        existing = self.users.get(username)
        if existing:
            existing["attributes"] = saml_user.attributes
            existing["issuer"] = saml_user.issuer
            existing["session_index"] = saml_user.session_index
            return existing

        user = {
            "username": username,
            "issuer": saml_user.issuer,
            "session_index": saml_user.session_index,
            "attributes": saml_user.attributes,
            "authn_contexts": saml_user.authn_contexts,
        }
        self.users[username] = user
        return user


